const input = $json.body ?? $json;

function isPlayable(url) {
  if (!url) return false;
  const normalized = String(url).toLowerCase();
  if (normalized.includes('youtube.com/watch') || normalized.includes('youtu.be/')) return false;
  if (normalized.includes('tiktok.com/') || normalized.includes('instagram.com/')) return false;
  if (normalized.includes('twitter.com/') || normalized.includes('x.com/')) return false;
  return normalized.startsWith('blob:') || normalized.includes('.mp4') || normalized.includes('.webm') || normalized.includes('.mov') || normalized.includes('.m3u8') || normalized.includes('r2.dev') || normalized.includes('cloudflare') || normalized.includes('cdn');
}

const assetUrl = input.cdn_url || input.video_url || input.rendered_video_url || input.processed_video_url;
if (!isPlayable(assetUrl)) {
  throw new Error(`Playable media URL required; got ${assetUrl || 'empty'}`);
}

const channelMap = {
  sports: 'a1000000-0000-0000-0000-000000000001',
  arena: 'a1000000-0000-0000-0000-000000000002',
  combat: 'a1000000-0000-0000-0000-000000000003',
  women: 'a1000000-0000-0000-0000-000000000004',
};

const channelId = input.channel_id || channelMap[input.channel];
if (!channelId) throw new Error(`Unknown channel: ${input.channel}`);

const uuidRe = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
const row = {
  channel_id: channelId,
  status: 'queued',
  source_video_url: input.source_video_url || null,
  video_url: assetUrl,
  cdn_url: assetUrl,
  rendered_video_url: assetUrl,
  processed_video_url: assetUrl,
  thumbnail_url: input.thumbnail_url || null,
  hook: input.caption || null,
  caption: input.caption || null,
  score: Number(input.score ?? 0),
  updated_at: new Date().toISOString(),
};

if (input.post_id && uuidRe.test(input.post_id)) {
  row.id = input.post_id;
}

return [{ json: row }];
